from __future__ import annotations

import json
import os
import re
from pathlib import Path
from typing import Any

from .grader import Grade

GRADE_JSON_SCHEMA: dict[str, Any] = {
    "type": "object",
    "properties": {
        "score": {
            "type": "integer",
            "description": "Count of rubric dimensions the prompt meaningfully demonstrates (0-7).",
        },
        "label": {
            "type": "string",
            "enum": ["above_bar", "below_bar"],
            "description": "Final classification for this prompt in context.",
        },
        "strengths": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Specific strengths tied to rubric dimensions.",
        },
        "gaps": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Specific gaps tied to rubric dimensions.",
        },
        "coaching": {
            "type": "string",
            "description": "One highest-impact coaching note for the next prompt.",
        },
        "better_prompt": {
            "type": "string",
            "description": "Rewritten prompt that would clear the bar.",
        },
    },
    "required": ["score", "label", "strengths", "gaps", "coaching", "better_prompt"],
    "additionalProperties": False,
}

SYSTEM_PROMPT_TEMPLATE = """You are a prompt-quality coach grading user prompts in Cursor AI sessions.

Grade ONLY the user's prompt. Use the assistant reply only as conversation context.

## Rubric
Score 1 point for each dimension the prompt meaningfully demonstrates:
1. insight — adds judgment/context, not just raw facts
2. timing — moves the conversation forward at the right moment
3. context — enough background for good decisions
4. risk — surfaces assumptions, risks, or clarifying questions
5. clarity — understandable and specific request
6. recommendation — user did homework and proposes direction
7. action — bias for action; avoids passive waiting

## Bar
- above_bar: score >= {min_score} AND genuine product/engineering judgment for this moment—not just information retrieval.
- below_bar: one-word or letter answers ("a", "b", "c"), terse replies without reasoning, vague asks, or prompts that offload thinking without context or a proposed direction.

## Examples of above_bar prompts
{above_bar_examples}

## Examples of below_bar prompts
- "c"
- "help me with this"
- "what do you think?" (with no context or proposed direction)

Be honest and consistent. Strengths and gaps must reference rubric dimensions specifically.
label must match the bar rules above.
Return valid JSON matching the required schema.
"""

DEFAULT_ABOVE_BAR_EXAMPLES = """- "Before connecting Google Docs API, help me define the exact local output format that would make manual review easy and later automation simple."
- "My goal is to prove the MVP works without building UI. Given we can read Cursor transcripts, what is the simplest pipeline to extract 50 prompt-response pairs, grade them, and show evidence to reviewers?"
"""


def _load_above_bar_examples(settings: dict) -> str:
    path = settings.get("approved_insights_file")
    if not path:
        return DEFAULT_ABOVE_BAR_EXAMPLES

    file_path = Path(path)
    if not file_path.is_file():
        return DEFAULT_ABOVE_BAR_EXAMPLES

    text = file_path.read_text(encoding="utf-8")
    prompts = re.findall(r"^\> (.+)$", text, flags=re.MULTILINE)
    if not prompts:
        return DEFAULT_ABOVE_BAR_EXAMPLES

    lines = [f'- "{prompt.strip()}"' for prompt in prompts[-5:]]
    return "\n".join(lines)


def _build_user_message(user_text: str, assistant_text: str, max_assistant_chars: int) -> str:
    assistant_excerpt = assistant_text.strip()
    if len(assistant_excerpt) > max_assistant_chars:
        assistant_excerpt = assistant_excerpt[:max_assistant_chars] + "\n...[truncated]"

    return (
        "Grade this user prompt.\n\n"
        f"USER PROMPT:\n{user_text.strip()}\n\n"
        f"ASSISTANT REPLY (context only):\n{assistant_excerpt or '[none]'}"
    )


def _parse_grade_payload(payload: dict[str, Any], user_text: str) -> Grade:
    score = int(payload["score"])
    score = max(0, min(7, score))

    label = str(payload["label"])
    if label not in {"above_bar", "below_bar"}:
        raise ValueError(f"Invalid label from LLM: {label!r}")

    strengths = [str(item).strip() for item in payload.get("strengths", []) if str(item).strip()]
    gaps = [str(item).strip() for item in payload.get("gaps", []) if str(item).strip()]
    coaching = str(payload["coaching"]).strip()
    better_prompt = str(payload["better_prompt"]).strip()

    if not coaching:
        coaching = "Make the next prompt more specific, contextual, and action-oriented."
    if not better_prompt:
        from .grader import build_better_prompt

        biggest_gap = gaps[0] if gaps else "Missing context and direction."
        better_prompt = build_better_prompt(user_text, biggest_gap)

    return Grade(
        score=score,
        label=label,
        strengths=strengths,
        gaps=gaps,
        coaching=coaching,
        better_prompt=better_prompt,
    )


def _resolve_api_key(settings: dict) -> str:
    provider = settings.get("llm_provider", "openai").lower()
    env_var = settings.get("llm_api_key_env", "OPENAI_API_KEY")

    if provider == "ollama":
        return os.environ.get(env_var) or settings.get("llm_api_key") or "ollama"

    api_key = os.environ.get(env_var) or settings.get("llm_api_key") or os.environ.get("OPENAI_API_KEY")
    if not api_key:
        raise RuntimeError(
            f"Set {env_var} in the environment or llm_api_key in config/settings.json "
            f"(provider={provider})"
        )
    return api_key


def _resolve_base_url(settings: dict) -> str | None:
    provider = settings.get("llm_provider", "openai").lower()
    base_url = settings.get("llm_base_url")

    if base_url:
        return str(base_url)

    if provider == "ollama":
        return "http://localhost:11434/v1"

    return None


def _create_client(settings: dict):
    try:
        from openai import OpenAI
    except ImportError as exc:
        raise RuntimeError("Install dependencies: pip install -r requirements.txt") from exc

    api_key = _resolve_api_key(settings)
    base_url = _resolve_base_url(settings)
    timeout = float(settings.get("llm_timeout_seconds", 30))

    if base_url:
        return OpenAI(api_key=api_key, base_url=base_url, timeout=timeout)
    return OpenAI(api_key=api_key, timeout=timeout)


def _request_structured_grade(client, settings: dict, system_prompt: str, user_message: str) -> dict[str, Any]:
    model = settings.get("llm_model", "gpt-4o-mini")
    provider = settings.get("llm_provider", "openai").lower()
    use_json_schema = provider != "ollama" or settings.get("llm_use_json_schema", False)

    kwargs: dict[str, Any] = {
        "model": model,
        "temperature": 0,
        "messages": [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_message},
        ],
    }

    if use_json_schema:
        kwargs["response_format"] = {
            "type": "json_schema",
            "json_schema": {
                "name": "prompt_grade",
                "strict": True,
                "schema": GRADE_JSON_SCHEMA,
            },
        }
    else:
        kwargs["response_format"] = {"type": "json_object"}

    response = client.chat.completions.create(**kwargs)
    content = response.choices[0].message.content
    if not content:
        raise RuntimeError("LLM returned an empty response")

    return json.loads(content)


def grade_prompt_llm(user_text: str, assistant_text: str, settings: dict) -> Grade:
    min_above_bar_score = int(settings.get("min_above_bar_score", 5))
    max_assistant_chars = int(settings.get("llm_max_assistant_chars", 2000))

    above_bar_examples = _load_above_bar_examples(settings)
    system_prompt = SYSTEM_PROMPT_TEMPLATE.format(
        min_score=min_above_bar_score,
        above_bar_examples=above_bar_examples,
    )
    user_message = _build_user_message(user_text, assistant_text, max_assistant_chars)

    client = _create_client(settings)
    payload = _request_structured_grade(client, settings, system_prompt, user_message)
    return _parse_grade_payload(payload, user_text)

